INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optician-moex-00809', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關眼球的胚胎發育，下列敘述何者正確？', '["水晶體於晶體囊泡（lensvesicle）形成，由玻璃狀體動脈（hyaloidartery）供給養分", "玻璃狀體血管（hyaloidvessels）主要位於眼球的水晶體，而非玻璃體", "玻璃狀體血管之後會形成視網膜動脈，而非靜脈", "淚腺與結膜囊（conjunctivalsac）的胚胎來源不同"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00810', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列有關出生後之眼球發育，何者錯誤？', '["在生命的最初幾年，眼球的大小迅速增加，之後增長速度放緩，但在青春期時再次增加", "水晶體在出生後迅速生長，並且在整個生命過程中不斷地生長", "眼睛的運動最初是不協調的，且可能存在短暫的偏離，這種情況到了第4個月應穩定下來", "淚腺在出生之後就有作用，新生兒哭的時候會伴隨著眼淚"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00811', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關眼窩內壁（medial orbital wall）特性之敘述，下列何者正確？①為眼窩壁最薄處  ②前部緊鄰篩竇', '["因為結構特性，經鼻感染風險極低", "後部緊鄰蝶竇（sphenoidalsinus）", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00812', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '上眼窩裂（superiororbitalfissure）位於眼窩頂（roof）與外壁（lateralwall）之間，有許多神經血管組織穿 越其中；眼外肌形成的一個共同肌腱環（common tendinous ring）將上眼窩裂間隔為幾個空間。下列那一 條神經行走於上眼窩裂中，但位於共同肌腱環之外？', '["動眼神經（第三對腦神經）", "外展神經（第六對腦神經）", "三叉神經的第二分支（第五對腦神經，maxillarybranch）", "滑車神經（第四對腦神經）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00813', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列何組織富含纖維層（fibrouslayer）可維持眼球的外形？①角膜（cornea）  ②懸韌帶纖維（zonularfiber）', '["水晶體纖維（lensfiber）", "鞏膜（sclera）", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 5, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00814', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '結膜（conjunctiva）分為三個部分，與角膜相連接為何者？', '["瞼結膜（palpebralconjunctiva）", "結膜穹窿（conjunctivalfornices）", "球結膜（bulbarconjunctiva）", "以上三個部分皆與角膜相連"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00815', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '當雙眼由遠看近時，最不會引發眼球的何種反應？', '["瞳孔變小", "睫狀肌收縮", "隅角變寬", "眼球向內集中"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00816', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '高度遠視的老年人，容易有隅角閉鎖性青光眼的急性發作。下列相關敘述何者錯誤？', '["高度遠視的老年人一般前房較淺，隅角較窄", "若有白內障，水晶體密度增加形狀變突，也可能致使虹膜前傾壓迫隅角", "隅角有小樑網（trabecularmeshwork），大部分的房水都是由此處排出的", "點散瞳劑也可能是造成急性發作的原因，因為睫狀肌麻痺，懸韌帶放鬆造成水晶體屈光度增加，向前突 出壓迫隅角"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00817', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '下列關於視網膜色素上皮層功能的敘述，何者錯誤？', '["吸收光線，防止光線散射", "儲存維生素A", "製造視紫質（rhodopsin）", "調節視紫質代謝"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-00818', 'optician', 'optician-moex-110-5e38135e', 'sub-optician-01', NULL, 'single_choice', '有關玻璃體（vitreous）的敘述，下列何者錯誤？', '["膠狀的玻璃體液化或經由手術切除後無法再度形成", "玻璃體含99%水分，另含有膠原蛋白、可溶性蛋白質及玻尿酸", "健康玻璃體乃無色透明膠狀物質，不含任何細胞，若有細胞代表發炎反應", "成年人的玻璃體容量約為4毫升（ml）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:30+00:00", "source_pdf_sha1": "d64008ebd39f", "answer_pdf_sha1": "b9075f02da7c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "113", "s": "1106", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "眼球構造與倫理法規概要", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
